import React, { useState, useEffect, useRef } from "react";
import { useNavigate, useParams } from "react-router-dom";
import Webcam from "react-webcam";
import axios from "../api/axios";

const StudyRoom = ({ markDayComplete }) => {
    const { day } = useParams(); // Get day from URL
    const navigate = useNavigate();
    const webcamRef = useRef(null);

    const [seconds, setSeconds] = useState(10); // Set to 10 for testing
    const [isActive, setIsActive] = useState(false);
    const [showQuiz, setShowQuiz] = useState(false);
    const [userAnswer, setUserAnswer] = useState("");

    useEffect(() => {
        let interval = null;
        if (isActive && seconds > 0) {
            interval = setInterval(() => setSeconds(prev => prev - 1), 1000);
        } else if (seconds === 0) {
            clearInterval(interval);
            setIsActive(false);
            setShowQuiz(true); 
        }
        return () => clearInterval(interval);
    }, [isActive, seconds]);

    const handleFinalSubmit = async () => {
        if (userAnswer.length < 5) {
            alert("Please provide a summary.");
            return;
        }

        try {
            // 1. Update State in App.js (This makes the dashboard green)
            markDayComplete(day);

            // 2. Optional: Update Backend
            // await axios.patch(`/tasks/${day}`, { status: "completed", explanation: userAnswer });
            
            // 3. Redirect
            navigate("/dashboard");
        } catch (error) {
            markDayComplete(day);
            navigate("/dashboard");
        }
    };

    return (
        <div style={{ textAlign: 'center', padding: '40px' }}>
            {!showQuiz ? (
                <>
                    <h2>Day {day}: Study Session</h2>
                    <div style={{ width: '400px', margin: '20px auto', border: '3px solid #333' }}>
                        <Webcam audio={false} ref={webcamRef} width="100%" />
                    </div>
                    <h1 style={{ fontSize: '4rem' }}>
                        {Math.floor(seconds / 60)}:{String(seconds % 60).padStart(2, '0')}
                    </h1>
                    <button onClick={() => setIsActive(!isActive)} style={{ padding: '10px 30px', cursor: 'pointer' }}>
                        {isActive ? 'Pause' : 'Start Focus'}
                    </button>
                </>
            ) : (
                <div style={{ maxWidth: '500px', margin: '0 auto' }}>
                    <h3>Time's Up! Summary:</h3>
                    <textarea 
                        value={userAnswer} 
                        onChange={(e) => setUserAnswer(e.target.value)} 
                        style={{ width: '100%', height: '100px' }}
                    />
                    <button onClick={handleFinalSubmit} style={{ marginTop: '20px', background: 'green', color: 'white', padding: '10px 30px' }}>
                        Finish & Update Dashboard
                    </button>
                </div>
            )}
        </div>
    );
};

export default Study;
